// ─── Main ─────────────────────────────────────────────────────────────────────

async function main() {
  console.log(`Seeding education programs (${PROGRAMS.length} total)...\n`);

  let inserted = 0;
  let skipped = 0;

  for (const program of PROGRAMS) {
    const [existing] = await db
      .select({ id: schema.educationProgramsTable.id })
      .from(schema.educationProgramsTable)
      .where(
        and(
          eq(schema.educationProgramsTable.name, program.name),
          eq(schema.educationProgramsTable.provider, program.provider)
        )
      )
      .limit(1);

    if (existing) {
      skipped++;
      continue;
    }

    await db.insert(schema.educationProgramsTable).values({
      name: program.name,
      provider: program.provider,
      programType: program.programType,
      duration: program.duration,
      cost: program.cost,
      roiScore: program.roiScore ?? null,
      tags: program.tags,
      url: program.url,
      description: program.description,
      isActive: true,
    });

    console.log(`  ✓ ${program.provider} — ${program.name}`);
    inserted++;
  }

  console.log(`\nDone. Inserted: ${inserted}, Skipped (already existed): ${skipped}`);
  console.log(`Total programs in seed file: ${PROGRAMS.length}`);
  process.exit(0);
}

main().catch((err) => {
  console.error("Seed failed:", err);
  process.exit(1);
});
